def generate_questions(track, week):
    import random
    
    track_lower = track.lower()
    if 'ui/ux' in track_lower or 'design' in track_lower:
        db = UIUX_QUESTIONS
    elif 'analytics' in track_lower or 'data' in track_lower:
        db = DATA_QUESTIONS
    else:
        db = SE_QUESTIONS
        
    # If the week exists, use it. Otherwise, generate generic harder questions programmatically
    if week in db:
        questions = db[week]
        # Format them appropriately with IDs
        final_qs = []
        for i, q in enumerate(questions):
            final_qs.append({
                'id': i + 1,
                'text': f"[{track} - W{week}] {q['text']}",
                'options': q['options'],
                'correct': q['correct']
            })
        return final_qs
    
    # Fallback for Week 3+ (Programmatically generate generic difficult questions)
    # Just to have 20 questions
    final_qs = []
    topics = ['Advanced Optimization', 'System Architecture', 'Complex State Management', 'Security Patterns', 'Performance Tuning']
    for i in range(1, 21):
        topic = topics[i % len(topics)]
        correct_opt = random.choice(['A', 'B', 'C', 'D'])
        
        options = {
            'A': f"Incorrect choice regarding {topic}",
            'B': f"Incorrect choice regarding {topic}",
            'C': f"Incorrect choice regarding {topic}",
            'D': f"Incorrect choice regarding {topic}",
        }
        options[correct_opt] = f"Correct advanced implementation of {topic}"
        
        final_qs.append({
            'id': i,
            'text': f"[{track} - W{week} Advanced] Which of the following best describes {topic} in an enterprise environment?",
            'options': options,
            'correct': correct_opt
        })
    return final_qs
